UPDATE t_daily_bill
customer_code = CASE
WHEN merchant_code = #{item.merchantCode} AND merchant_name = #{item.merchantName} THEN #{item.customerCode}
ELSE customer_code END, customer_name = CASE
WHEN merchant_code = #{item.merchantCode} AND merchant_name = #{item.merchantName} THEN #{item.customerName}
ELSE customer_name END, emp_name = CASE
WHEN merchant_code = #{item.merchantCode} AND merchant_name = #{item.merchantName} AND #{item.empName} IS NOT NULL AND #{item.empName} != '' THEN #{item.empName}
ELSE emp_name END, emp_type = CASE
WHEN merchant_code = #{item.merchantCode} AND merchant_name = #{item.merchantName} AND #{item.empType} IS NOT NULL AND #{item.empType} != '' THEN #{item.empType}
ELSE emp_type END
WHERE (merchant_code, merchant_name) IN
(#{item.merchantCode}, #{item.merchantName})
